import{_ as a,o as t,c as r,a2 as n}from"./chunks/framework.N9BN-Nr4.js";const p=JSON.parse('{"title":"Hitmen","description":"","frontmatter":{},"headers":[],"relativePath":"formats/assassin/variants/hitmen.md","filePath":"formats/assassin/variants/hitmen.md","lastUpdated":1782025909000}'),o={name:"formats/assassin/variants/hitmen.md"};function i(s,e,l,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="hitmen" tabindex="-1">Hitmen <a class="header-anchor" href="#hitmen" aria-label="Permalink to &quot;Hitmen&quot;">​</a></h1><p>Hitmen is a local variant of the broader Assassin format. Each player receives a secret Mark. Instead of a normal free-for-all, players can only attack or target their current Mark unless the rules below expand their legal targets.</p><h2 id="terminology" tabindex="-1">Terminology <a class="header-anchor" href="#terminology" aria-label="Permalink to &quot;Terminology&quot;">​</a></h2><ul><li>A <strong>Mark Card</strong> is the numbered card dealt to a player to indicate their assigned target.</li><li>A player&#39;s <strong>Mark</strong> is the player indicated by their current Mark Card.</li><li>A player&#39;s <strong>Sphere</strong> consists of that player and anything targetable that player controls. This includes permanents, tokens, spells and abilities on the stack, and any other targetable game object a card or rule may care about.</li></ul><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><ul><li>Mark Cards are numbered <code>1</code> through <code>X</code>, where <code>X</code> is the number of players.</li><li>Each player receives one Mark Card.</li><li>Each number corresponds to another player.</li></ul><h2 id="targeting-rules" tabindex="-1">Targeting Rules <a class="header-anchor" href="#targeting-rules" aria-label="Permalink to &quot;Targeting Rules&quot;">​</a></h2><ul><li>You may only attack your Mark.</li><li>Your spells and abilities may only target your Mark&#39;s Sphere.</li><li>If you do not have enough valid targets, you may also target the Spheres of players next to your Mark.</li><li>If you still do not have enough valid targets, continue expanding outward from the previous set of players until the effect can be completed or all players are included.</li><li>When an effect on the stack affects you or anything you control, even if it does not target, you may target that effect or its controller&#39;s Sphere until the stack resolves.</li></ul><h2 id="changing-marks" tabindex="-1">Changing Marks <a class="header-anchor" href="#changing-marks" aria-label="Permalink to &quot;Changing Marks&quot;">​</a></h2><p>When your Mark dies, take their Mark Card. That card indicates your new Mark.</p><p>If a player ever has their own number as a Mark Card, including during setup, they become a Free Agent and may attack or target anyone.</p><h2 id="win-condition" tabindex="-1">Win Condition <a class="header-anchor" href="#win-condition" aria-label="Permalink to &quot;Win Condition&quot;">​</a></h2><p>Be the last player standing.</p><p>As a shorter game option, the table may set a required number of kills instead.</p>',14)])])}const m=a(o,[["render",i]]);export{p as __pageData,m as default};
